int main() {
    int nums[] = {1, 2, 1, 1, 3, 2, 2};
    int n = sizeof(nums) / sizeof(nums[0]);
    int result[2];
    int count = 0;
    for (int i = 0; i < n; i++) {
        int freq = 0;
        for (int j = 0; j < n; j++) {
            if (nums[i] == nums[j]) {
                freq++;
            }
        }
        if (freq > n / 3 && count < 2) {
            result[count] = nums[i];
            count++;
        }
    }
    printf("The majority elements are: ");
    for (int i = 0; i < count; i++) {
        printf("%d ", result[i]);
    }
    printf("\n");
    return 0;
}

